patch:
diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index 86de89595957..278bef0aef0a 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -524,9 +524,20 @@ static Decomposition decompose(Value *V,
         V = Op0;
     }

-    if (match(V, m_NSWAdd(m_Value(Op0), m_Value(Op1))))
+    if (match(V, m_NSWAdd(m_Value(Op0), m_Value(Op1)))) {
       return MergeResults(Op0, Op1, IsSigned);
+    }

+    if (match(V, m_NSWSub(m_Value(Op0), m_Value(Op1)))) {
+      auto ResA = decompose(Op0, Preconditions, IsSigned, DL);
+      auto ResB = decompose(Op1, Preconditions, IsSigned, DL);
+      ResA.sub(ResB);
+      if (isKnownNonNegative(Op0, DL))
+        ResA.Vars.push_back({0, Op0, true});
+      if (isKnownNonNegative(Op1, DL))
+        ResA.Vars.push_back({0, Op1, true});
+      return ResA;
+    }
     ConstantInt *CI;
     if (match(V, m_NSWMul(m_Value(Op0), m_ConstantInt(CI))) && canUseSExt(CI)) {
       auto Result = decompose(Op0, Preconditions, IsSigned, DL);
@@ -679,7 +690,6 @@ ConstraintInfo::getConstraint(CmpInst::Predicate Pred, Value *Op0, Value *Op1,
   int64_t Offset1 = ADec.Offset;
   int64_t Offset2 = BDec.Offset;
   Offset1 *= -1;
-
   auto &VariablesA = ADec.Vars;
   auto &VariablesB = BDec.Vars;

@@ -713,7 +723,7 @@ ConstraintInfo::getConstraint(CmpInst::Predicate Pred, Value *Op0, Value *Op1,
   auto &R = Res.Coefficients;
   for (const auto &KV : VariablesA) {
     R[GetOrAddIndex(KV.Variable)] += KV.Coefficient;
-    auto I =
+        auto I = KnownNonNegativeVariables.insert(std::make_pair(KV.Variable, KV.IsKnownNonNegative));
         KnownNonNegativeVariables.insert({KV.Variable, KV.IsKnownNonNegative});
     I.first->second &= KV.IsKnownNonNegative;
   }
@@ -722,7 +732,7 @@ ConstraintInfo::getConstraint(CmpInst::Predicate Pred, Value *Op0, Value *Op1,
     if (SubOverflow(R[GetOrAddIndex(KV.Variable)], KV.Coefficient,
                     R[GetOrAddIndex(KV.Variable)]))
       return {};
-    auto I =
+        auto I = KnownNonNegativeVariables.insert(std::make_pair(KV.Variable, KV.IsKnownNonNegative));
         KnownNonNegativeVariables.insert({KV.Variable, KV.IsKnownNonNegative});
     I.first->second &= KV.IsKnownNonNegative;
   }

